update public.lessons l set enhancements = $ench${"industryStory":"A strong tester bombed an interview because they expected only technical questions and froze at the behavioural round and a live test task. They had the skills — they just did not know the shape of the process. Knowing the stages turns surprise into preparation.","visualAid":{"type":"timeline","title":"A typical QA interview process","steps":[{"label":"Application / screen","detail":"CV + recruiter call"},{"label":"Technical interview","detail":"testing fundamentals"},{"label":"Behavioural","detail":"teamwork, scenarios (STAR)"},{"label":"Test task","detail":"design tests / find bugs"},{"label":"Final / offer","detail":"fit + negotiation"}]},"davidTip":"Prepare for each stage deliberately — fundamentals for the technical round, STAR stories for behavioural, a calm method for test tasks. As an interviewer, I can always tell who understood the process and who just turned up hoping.","miniChallenge":"Map the stages you expect for a junior QA role and note one way you would prepare for each.","modelAnswer":"## Example\nScreen: tight CV + a 60-second intro. Technical: revise severity/priority, test design, STLC. Behavioural: 5 STAR stories. Test task: a structured approach (analyse → design → document). Final: research the company + prepare questions.","resourcePreview":{"name":"Interview Day Checklist","purpose":"Everything to prepare before, during and after the interview.","whenToUse":"Use it to build your per-stage preparation plan.","formats":["PDF","DOCX"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 1 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"Two candidates gave near-identical technical answers. One got the offer because they also showed clear communication, collaboration and a learning mindset — the things interviewers are really assessing beneath the questions.","visualAid":{"type":"comparison","title":"What employers are really assessing","headers":["Question on the surface","What they are really checking"],"rows":[["\"How would you test X?\"","Structured thinking & coverage"],["\"Tell me about a conflict\"","Communication & maturity"],["\"A defect you are proud of\"","Impact & ownership"],["\"Why testing?\"","Genuine motivation & fit"]]},"davidTip":"Behind every question is a trait being assessed: structured thinking, communication, ownership, fit. Answer the question, but also show the trait — that is what separates two technically-correct candidates.","miniChallenge":"For three common questions, write the underlying trait the interviewer is assessing.","modelAnswer":"## Example\n\"How do you stop testing?\" → risk-based judgement. \"A time you disagreed with a dev\" → collaboration. \"Why this company?\" → motivation and research/fit."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 1 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A candidate \"revised everything\" the night before and remembered little. Another prepared systematically over a week — fundamentals, STAR stories, company research, mock practice — and walked in calm. Effective preparation beats frantic cramming every time.","davidTip":"Spread preparation across the week and practise out loud, not just in your head. The calm that comes from genuine readiness is visible in an interview — and it is mostly preparation, not personality.","miniChallenge":"Draft a one-week interview-prep plan with a focus for each day (fundamentals, STAR, company research, mock, rest).","modelAnswer":"## Example\nMon: testing fundamentals. Tue: 5 STAR stories. Wed: test-task practice. Thu: company research + questions to ask. Fri: full mock interview. Sat: refine weak areas. Sun: light review + rest.","portfolioBuilder":"Your QA portfolio (from the 90-Day course or your own work) is a powerful interview asset — plan to reference it. Note which artefacts you will mention for which questions."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = 'qa-interview-accelerator'
  and m.module_number = 1 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, show you understand the whole process and have a concrete prep plan — not just \"I'll revise\". Interviewers value candidates who approach the interview itself methodically.","miniChallenge":"Before submitting, sanity-check your prep plan covers every interview stage you identified.","managersReview":{"intro":"If I assessed your interview-prep plan as a hiring manager, I would look for:","strengths":["Awareness of all interview stages","A realistic, spread-out prep plan","Use of the portfolio as evidence"],"gaps":["Only technical prep","Cramming the night before","No behavioural or test-task prep"],"improvements":["Prepare for each stage","Practise answers out loud","Plan which portfolio pieces to mention"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
